32: #define SCRIPT_INSTANCE_H
33: 
34: #include "core/object/ref_counted.h"
35: 
36: class Script;
37: class ScriptLanguage;
38: 
39: class ScriptInstance {
40: public:
41: 	virtual bool set(const StringName &p_name, const Variant &p_value) = 0;
42: 	virtual bool get(const StringName &p_name, Variant &r_ret) const = 0;
43: 	virtual void get_property_list(List<PropertyInfo> *p_properties) const = 0;
44: 	virtual Variant::Type get_property_type(const StringName &p_name, bool *r_is_valid = nullptr) const = 0;
45: 	virtual void validate_property(PropertyInfo &p_property) const = 0;
46: 
47: 	virtual bool property_can_revert(const StringName &p_name) const = 0;
48: 	virtual bool property_get_revert(const StringName &p_name, Variant &r_ret) const = 0;
49: 
50: 	virtual Object *get_owner() { return nullptr; }
51: 	virtual void get_property_state(List<Pair<StringName, Variant>> &state);
52: 
53: 	virtual void get_method_list(List<MethodInfo> *p_list) const = 0;
54: 	virtual bool has_method(const StringName &p_method) const = 0;
55: 
56: 	virtual int get_method_argument_count(const StringName &p_method, bool *r_is_valid = nullptr) const;
57: 
58: 	virtual Variant callp(const StringName &p_method, const Variant **p_args, int p_argcount, Callable::CallError &r_error) = 0;
59: 
60: 	template <typename... VarArgs>
61: 	Variant call(const StringName &p_method, VarArgs... p_args) {
62: 		Variant args[sizeof...(p_args) + 1] = { p_args..., Variant() }; // +1 makes sure zero sized arrays are also supported.
63: 		const Variant *argptrs[sizeof...(p_args) + 1];
64: 		for (uint32_t i = 0; i < sizeof...(p_args); i++) {
65: 			argptrs[i] = &args[i];
66: 		}
67: 		Callable::CallError cerr;
68: 		return callp(p_method, sizeof...(p_args) == 0 ? nullptr : (const Variant **)argptrs, sizeof...(p_args), cerr);
69: 	}
70: 
71: 	virtual Variant call_const(const StringName &p_method, const Variant **p_args, int p_argcount, Callable::CallError &r_error); // implement if language supports const functions
72: 	virtual void notification(int p_notification, bool p_reversed = false) = 0;
73: 	virtual String to_string(bool *r_valid) {
74: 		if (r_valid) {
75: 			*r_valid = false;
76: 		}
77: 		return String();
78: 	}
79: 
80: 	//this is used by script languages that keep a reference counter of their own
81: 	//you can make Ref<> not die when it reaches zero, so deleting the reference
82: 	//depends entirely from the script
83: 
84: 	virtual void refcount_incremented() {}
85: 	virtual bool refcount_decremented() { return true; } //return true if it can die
86: 
87: 	virtual Ref<Script> get_script() const = 0;
88: 
89: 	virtual bool is_placeholder() const { return false; }
90: 
91: 	virtual void property_set_fallback(const StringName &p_name, const Variant &p_value, bool *r_valid);
92: 	virtual Variant property_get_fallback(const StringName &p_name, bool *r_valid);
93: 
94: 	virtual const Variant get_rpc_config() const;
95: 
96: 	virtual ScriptLanguage *get_language() = 0;
97: 	virtual ~ScriptInstance();
98: };
99: 
100: #endif // SCRIPT_INSTANCE_H
